#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int n;
    scanf("%d", &n);
    int positions[n], coverages[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &positions[i]);
    }
    for (int i = 0; i < n; i++) {
        scanf("%d", &coverages[i]);
    }
    qsort(positions, n, sizeof(int), compare);
    qsort(coverages, n, sizeof(int), compare);
    int count = 0;
    int current_position = 0;
    for (int i = 0; i < n; i++) {
        if (positions[i] > current_position) {
            count++;
            current_position = positions[i] + coverages[i];
        }
    }
    printf("%d\n", count);
    return 0;
}

