const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let positions = [];
let coverages = [];
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else if (positions.length < n) {
        positions = input.split(' ').map(Number);
    } else if (coverages.length < n) {
        coverages = input.split(' ').map(Number);
        positions.sort((a, b) => a - b);
        coverages.sort((a, b) => a - b);
        let count = 0;
        let current_position = 0;
        for (let i = 0; i < n; i++) {
            if (positions[i] > current_position) {
                count++;
                current_position = positions[i] + coverages[i];
            }
        }
        console.log(count);
        rl.close();
    }
});

